/**
 * embed-papers.cjs — Generate embeddings for paper knowledge base
 * Usage: DASHSCOPE_API_KEY=xxx node scripts/embed-papers.cjs
 * Input: fc/papers_text.json (generated by scripts/extract-papers.py)
 * Output: fc/embeddings_papers.json
 */
const fs = require('fs');
const https = require('https');

const DASHSCOPE_KEY = process.env.DASHSCOPE_API_KEY;
if (!DASHSCOPE_KEY) {
  console.error('Error: DASHSCOPE_API_KEY is required.');
  process.exit(1);
}

const BATCH = 6;
const papers = JSON.parse(fs.readFileSync('fc/papers_text.json', 'utf8'));
console.log(`Loaded ${papers.length} chunks from ${new Set(papers.map(p => p.paperId)).size} papers`);

async function embedAll() {
  const batches = [];
  for (let i = 0; i < papers.length; i += BATCH) {
    batches.push(papers.slice(i, i + BATCH));
  }

  let done = 0;
  for (const batch of batches) {
    const texts = batch.map(p => (p.title + ' ' + p.text).substring(0, 2048));
    const embeddings = await callBailian(texts);
    batch.forEach((p, j) => { p.vec = embeddings[j]; });
    done += batch.length;
    process.stdout.write(`\r  ${done}/${papers.length} chunks`);
    await sleep(100);
  }

  const output = {
    version: 1,
    dim: 2048,
    model: 'text-embedding-v4',
    generated: new Date().toISOString(),
    papers: papers.map(p => ({
      id: p.id, paperId: p.paperId, title: p.title,
      dataset: p.dataset, text: p.text.substring(0, 300), vec: p.vec,
    })),
  };

  fs.writeFileSync('fc/embeddings_papers.json', JSON.stringify(output));
  const sizeMB = (fs.statSync('fc/embeddings_papers.json').size / 1024 / 1024).toFixed(2);
  console.log(`\n✅ Saved fc/embeddings_papers.json (${sizeMB} MB)`);
}

function callBailian(texts) {
  return new Promise((resolve, reject) => {
    const body = JSON.stringify({
      model: 'text-embedding-v4',
      input: texts,
      dimensions: 2048,
      encoding_format: 'float',
    });

    const req = https.request({
      hostname: 'dashscope.aliyuncs.com',
      path: '/compatible-mode/v1/embeddings',
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${DASHSCOPE_KEY}`,
        'Content-Type': 'application/json',
      },
    }, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.code) return reject(new Error(`${json.code}: ${json.message}`));
          resolve(json.data.map(d => d.embedding));
        } catch (e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

embedAll().catch(e => { console.error(e); process.exit(1); });
